1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Step = { op: "quote"; items: Item[] };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_THRESHOLD_YEARS = 2;
13	
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PRICE = 60;
16	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const countByType = (items: Item[]): Record<string, number> => {
28	  const counts: Record<string, number> = {};
29	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
30	  return counts;
31	};
32	
33	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
34	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
35	
36	const lineItemPrice = (type: string, count: number): number =>
37	  qualifiesForComponentBlock(type, count)
38	    ? COMPONENT_BLOCK_PRICE
39	    : BASE_PREMIUM[type] * count;
40	
41	const sumBasePremiums = (items: Item[]): number =>
42	  Object.entries(countByType(items))
43	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
44	
45	const curseSurchargeFor = (item: Item): number =>
46	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE : 0;
47	
48	const highEnchantmentSurchargeFor = (item: Item): number =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
50	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
51	    : 0;
52	
53	const itemSurcharges = (items: Item[]): number =>
54	  items.reduce((sum, item) => sum + curseSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
55	
56	const loyaltyDiscountFor = (customer: Customer, basePremium: number): number =>
57	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
58	    ? basePremium * LOYALTY_DISCOUNT_RATE
59	    : 0;
60	
61	const quotePremium = (items: Item[], customer: Customer): number => {
62	  const basePremium = sumBasePremiums(items);
63	  const surcharges = itemSurcharges(items);
64	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
65	  const loyaltyDiscount = loyaltyDiscountFor(customer, basePremium);
66	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE);
67	};
68	
69	export const runScenario = (input: unknown): unknown => {
70	  const scenario = input as Scenario;
71	  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items, scenario.customer) }));
72	  return { results };
73	};
